<?php require __DIR__.'/../lib/functions.php'; $slug=$_GET['quiz']??''; $file=__DIR__.'/../data/quizzes/'.basename($slug).'.json'; if(!is_file($file))exit('Nicht gefunden'); if($_SERVER['REQUEST_METHOD']==='POST'){ $data=json_decode(file_get_contents($file),true); foreach(['title','shortTitle','category','icon','color','softColor','accent','coverImage','description','longDescription','seoTitle','seoDescription','roundLength'] as $k){ if(isset($_POST[$k])) $data[$k]=$_POST[$k]; } if(isset($_POST['questionCounts'])) $data['questionCounts']=array_values(array_filter(array_map('intval',explode(',',$_POST['questionCounts'])))); if(isset($_POST['tags'])) $data['tags']=array_values(array_filter(array_map('trim',explode(',',$_POST['tags'])))); file_put_contents($file,json_encode($data,JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT)); header('Location: quiz.php?quiz='.rawurlencode($slug).'&saved=1'); exit; } $q=json_decode(file_get_contents($file),true); ?><!doctype html><html lang="de"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Konfiguration</title><link rel="stylesheet" href="<?=asset_url('assets/css/portal.css')?>?v=<?=filemtime(__DIR__.'/../assets/css/portal.css')?>">
<link rel="stylesheet" href="../assets/css/design-system.css">
</head><body><main class="site"><div class="topbar"><h1><?=h($q['title'])?></h1><a href="index.php">Backend</a></div><?php if(isset($_GET['saved'])): ?><div class="notice">Gespeichert.</div><?php endif; ?><form method="post" class="card"><div class="form-row"><label>Titel<input name="title" value="<?=h($q['title'])?>"></label><label>Kurzname<input name="shortTitle" value="<?=h($q['shortTitle'])?>"></label></div><div class="form-row"><label>Kategorie<input name="category" value="<?=h($q['category'])?>"></label><label>Icon<input name="icon" value="<?=h($q['icon'])?>"></label></div><div class="form-row"><label>Farbe<input type="color" name="color" value="<?=h($q['color'])?>"></label><label>Soft-Farbe<input type="color" name="softColor" value="<?=h($q['softColor'] ?? '#f5eefc')?>"></label></div><div class="form-row"><label>Akzent<input type="color" name="accent" value="<?=h($q['accent'] ?? '#ffe08a')?>"></label><label>Cover-Bildpfad<input name="coverImage" value="<?=h($q['coverImage'] ?? '')?>"></label></div><label>Beschreibung<textarea name="description"><?=h($q['description'])?></textarea></label><label>Lange Beschreibung<textarea name="longDescription"><?=h($q['longDescription'] ?? '')?></textarea></label><label>SEO Title<input name="seoTitle" value="<?=h($q['seoTitle'])?>"></label><label>SEO Description<textarea name="seoDescription"><?=h($q['seoDescription'])?></textarea></label><div class="form-row"><label>Standard-Fragen pro Runde<input name="roundLength" type="number" value="<?=h($q['roundLength'])?>"></label><label>Fragenanzahlen, Komma getrennt<input name="questionCounts" value="<?=h(implode(',', $q['questionCounts'] ?? []))?>"></label></div><label>Tags, Komma getrennt<input name="tags" value="<?=h(implode(',', $q['tags'] ?? []))?>"></label><button class="btn">Speichern</button></form></main></body></html>
